class User_Model_UserMeta extends User_Model_Base_UserMeta
{

    public static function getUserMetasByUserID(int $ID) {
        $query = Doctrine_Query::create();
        $query->from('User_Model_UserMeta um');
        $query->where('um.User_ID = ?', $ID);
        return $query->execute();
    }

    public static function getUserMetaByID(int $id) {
        $query = Doctrine_Query::create();
        $query->from('User_Model_UserMeta um');
        $query->where('um.ID = ?', $id);
        return $query->fetchOne();
    }

    public static function deleteCustomerMetas(int $customerID) {
        $query = Doctrine_Query::create();
        $query->delete('User_Model_UserMeta um');
        $query->where('um.User_ID = ?', $customerID);
        $query->execute();
    }
